import com.fasterxml.jackson.databind.ObjectMapper;

public class RDF4JProtocolSessionTraceHarnessTest extends SPARQLProtocolSessionTest {

	private static final ObjectMapper MAPPER = new ObjectMapper();
	private static final String TEST_HEADER = "X-testing-header";
	private static final String TEST_VALUE = "foobar";
	private static final List<String> FILTERS = List.of("BOUND(?s)", "?s != <urn:blocked>");
	private static final Map<String, String> INPUT_BINDINGS = Map.of("seed", "<urn:seed>");
	private static final Map<String, String> OUTPUT_BINDINGS = Map.of("s", "<urn:subject>");
	private static final Map<String, String> RESULT_BINDINGS = Map.of("flag", "\"kept\"");

	@Override
	RDF4JProtocolSession createProtocolSession() {
		RDF4JProtocolSession session = new SharedHttpClientSessionManager().createRDF4JProtocolSession(serverURL);
		session.setRepository(Protocol.getRepositoryLocation(serverURL, repositoryID));
		HashMap<String, String> additionalHeaders = new HashMap<>();
		additionalHeaders.put(TEST_HEADER, TEST_VALUE);
		session.setAdditionalHttpHeaders(additionalHeaders);
		return session;
	}

	private RDF4JProtocolSession getRDF4JSession() {
		return (RDF4JProtocolSession) sparqlSession;
	}

	@Test
	public void testSendQueryTraceShouldSupportRichPayloadMatrix(MockServerClient client) throws Exception {
		List<TracePayloadCase> cases = buildCases();
		assertThat(cases).hasSize(96);

		for (TracePayloadCase testCase : cases) {
			client.when(
					request()
							.withMethod("POST")
							.withPath("/rdf4j-server/repositories/test")
							.withQueryStringParameter("trace", "true")
							.withQueryStringParameter("trace-request-id", testCase.requestId)
							.withHeader(TEST_HEADER, TEST_VALUE)
							.withHeader("Accept", "application/json"),
					Times.once())
					.respond(
							response()
									.withBody(MAPPER.writeValueAsString(testCase.payload))
									.withContentType(MediaType.APPLICATION_JSON));

			try (QueryTraceRequestContext.Activation ignored = QueryTraceRequestContext.activate(testCase.requestId)) {
				QueryTrace trace = getRDF4JSession().sendQueryTrace(QueryLanguage.SPARQL,
						"SELECT * WHERE { ?s ?p ?o }", null, null, true, 0);
				assertTraceMatches(testCase, trace);
			}
		}
	}

	private static List<TracePayloadCase> buildCases() {
		List<TracePayloadCase> cases = new ArrayList<>();
		int index = 0;
		for (TraceLayout layout : TraceLayout.values()) {
			for (TraceEvent event : TraceEvent.values()) {
				for (boolean distinct : List.of(false, true)) {
					for (boolean includeFilters : List.of(false, true)) {
						for (boolean error : List.of(false, true)) {
							cases.add(new TracePayloadCase(
									"case-" + index,
									"req-" + index,
									layout,
									event,
									distinct,
									includeFilters,
									error,
									createPayload(layout, event, distinct, includeFilters, error, "case-" + index)));
							index++;
						}
					}
				}
			}
		}
		return cases;
	}

	private static QueryTrace createPayload(TraceLayout layout, TraceEvent event, boolean distinct,
			boolean includeFilters, boolean error, String label) {
		List<QueryTrace.Line> lines = layout.includesLines()
				? List.of(new QueryTrace.Line("line-0", 0, 0, lineKind(event), lineText(event), 1))
				: List.of();
		List<QueryTrace.Pattern> patterns = layout.includesPatterns()
				? List.of(new QueryTrace.Pattern("sp-0", 0, "?s ?p ?o"))
				: List.of();
		QueryTrace.Frame frame = new QueryTrace.Frame(
				0,
				event.value,
				layout.includesLines() ? "line-0" : null,
				layout.includesLines() ? 0 : -1,
				layout.includesPatterns() ? "sp-0" : null,
				layout.includesPatterns() ? 0 : 0,
				INPUT_BINDINGS,
				OUTPUT_BINDINGS,
				RESULT_BINDINGS);
		QueryTrace trace = QueryTrace.success(lines, patterns, List.of(frame), distinct,
				includeFilters ? FILTERS : List.of());
		if (error) {
			trace.setError(new QueryTrace.Error("traceRequestFailed", "simulated-" + label));
		}
		return trace;
	}

	private static void assertTraceMatches(TracePayloadCase testCase, QueryTrace trace) {
		assertThat(trace.isSuccess()).isEqualTo(!testCase.error);
		assertThat(trace.isDistinct()).isEqualTo(testCase.distinct);
		assertThat(trace.getFilters()).isEqualTo(testCase.includeFilters ? FILTERS : List.of());
		assertThat(trace.getLines()).hasSize(testCase.layout.includesLines() ? 1 : 0);
		assertThat(trace.getPatterns()).hasSize(testCase.layout.includesPatterns() ? 1 : 0);
		assertThat(trace.getFrames()).hasSize(1);

		QueryTrace.Frame frame = trace.getFrames().get(0);
		assertThat(frame.getEvent()).isEqualTo(testCase.event.value);
		assertThat(frame.getInputBindings()).isEqualTo(INPUT_BINDINGS);
		assertThat(frame.getOutputBindings()).isEqualTo(OUTPUT_BINDINGS);
		assertThat(frame.getResultBindings()).isEqualTo(RESULT_BINDINGS);
		if (testCase.layout.includesLines()) {
			assertThat(trace.getLines().get(0).getKind()).isEqualTo(lineKind(testCase.event));
			assertThat(trace.getLines().get(0).getText()).isEqualTo(lineText(testCase.event));
			assertThat(trace.getLines().get(0).getStepIndex()).isEqualTo(0);
			assertThat(frame.getLineId()).isEqualTo("line-0");
			assertThat(frame.getStepIndex()).isEqualTo(0);
		} else {
			assertThat(frame.getLineId()).isNull();
			assertThat(frame.getStepIndex()).isEqualTo(-1);
		}
		if (testCase.layout.includesPatterns()) {
			assertThat(trace.getPatterns().get(0).getId()).isEqualTo("sp-0");
			assertThat(frame.getPatternId()).isEqualTo("sp-0");
			assertThat(frame.getPatternIndex()).isEqualTo(0);
		} else {
			assertThat(frame.getPatternId()).isNull();
		}
		if (testCase.error) {
			assertThat(trace.getError()).isNotNull();
			assertThat(trace.getError().getCode()).isEqualTo("traceRequestFailed");
			assertThat(trace.getError().getMessage()).isEqualTo("simulated-" + testCase.label);
		} else {
			assertThat(trace.getError()).isNull();
		}
	}

	private static String lineKind(TraceEvent event) {
		switch (event) {
		case MATCH:
			return "values";
		case DROP:
			return "minus";
		case RESULT:
			return "bind";
		case PROBE:
		default:
			return "pattern";
		}
	}

	private static String lineText(TraceEvent event) {
		switch (event) {
		case MATCH:
			return "VALUES ?s { <urn:test> }";
		case DROP:
			return "MINUS (new scope) {";
		case RESULT:
			return "BIND(?seed AS ?s)";
		case PROBE:
		default:
			return "?s ?p ?o";
		}
	}

	private enum TraceLayout {
		LEGACY_ONLY(false, true),
		LINE_ONLY(true, false),
		MIXED(true, true);

		private final boolean includesLines;
		private final boolean includesPatterns;

		TraceLayout(boolean includesLines, boolean includesPatterns) {
			this.includesLines = includesLines;
			this.includesPatterns = includesPatterns;
		}

		private boolean includesLines() {
			return includesLines;
		}

		private boolean includesPatterns() {
			return includesPatterns;
		}
	}

	private enum TraceEvent {
		PROBE("probe"),
		MATCH("match"),
		DROP("drop"),
		RESULT("result");

		private final String value;

		TraceEvent(String value) {
			this.value = value;
		}
	}

	private static final class TracePayloadCase {
		private final String label;
		private final String requestId;
		private final TraceLayout layout;
		private final TraceEvent event;
		private final boolean distinct;
		private final boolean includeFilters;
		private final boolean error;
		private final QueryTrace payload;

		private TracePayloadCase(String label, String requestId, TraceLayout layout, TraceEvent event,
				boolean distinct, boolean includeFilters, boolean error, QueryTrace payload) {
			this.label = label;
			this.requestId = requestId;
			this.layout = layout;
			this.event = event;
			this.distinct = distinct;
			this.includeFilters = includeFilters;
			this.error = error;
			this.payload = payload;
		}
	}
}
